function detectProvider(voiceId) {
  if (!voiceId) return "vapi";

  const v = voiceId.trim();

  // Rule 1: If ID contains ANY number → ElevenLabs
  if (/\d/.test(v)) {
    return "elevenlabs";
  }

  // Rule 2: If ID is alphabetic-only and short → WAPI
  if (/^[a-zA-Z]+$/.test(v) && v.length <= 10) {
    return "vapi";
  }

  // Fallback (safety net)
  return "elevenlabs";
}

return input.map(item => {
