  const voiceId = String(voice).trim();

  return {
    json: {
      voiceId,
      provider: detectProvider(voiceId),
      language: "en",
      originalLanguage: ""
    }
  };
});

const input = $input.all();

function scoreProvider(voiceId) {
  let score = {
    vapi: 0,
    elevenlabs: 0
  };

  const v = voiceId.trim();

  // Rule 1: Numeric presence
  if (/\d/.test(v)) {
    score.elevenlabs += 3;
  } else {
    score.vapi += 2;
  }

  // Rule 2: Alphabetic-only
  if (/^[a-zA-Z]+$/.test(v)) {
    score.vapi += 3;
  } else {
    score.elevenlabs += 2;
  }

  // Rule 3: Length profile
  if (v.length <= 10) {
    score.vapi += 2;
  } else if (v.length >= 14) {
    score.elevenlabs += 2;
  }

  // Rule 4: Case entropy
  const hasUpper = /[A-Z]/.test(v);
  const hasLower = /[a-z]/.test(v);

  if (hasUpper && hasLower) {
    score.elevenlabs += 1;
  } else {
    score.vapi += 1;
  }

  // Rule 5: Name-like structure (TitleCase)
  if (/^[A-Z][a-z]+$/.test(v)) {
    score.vapi += 2;
  }

  // Final decision
  if (score.elevenlabs > score.vapi) {
    return "elevenlabs";
  }

  return "vapi";
}

return input.map(item => {
  const voice =
    item.json?.body?.voice ??
    item.json?.voice ??
    "";

  const voiceId = String(voice).trim();

  return {
    json: {
      voiceId,
      provider: scoreProvider(voiceId),
      language: "en",
      originalLanguage: ""
    }
  };
});

