function detectProvider(rawVoiceId) {
  if (!rawVoiceId) return "vapi";

  const original = rawVoiceId.trim();

  // Normalized version for analysis (spaces removed)
  const v = original.replace(/\s+/g, "");

  let score = {
    vapi: 0,
    elevenlabs: 0
  };

  // Rule 1: Spaces strongly indicate human-readable names
  if (/\s/.test(original)) {
    score.vapi += 3;
  }

  // Rule 2: Numeric presence (after space removal)
  if (/\d/.test(v)) {
    score.elevenlabs += 3;
  } else {
    score.vapi += 2;
  }

  // Rule 3: Alphabetic-only (after normalization)
  if (/^[a-zA-Z]+$/.test(v)) {
    score.vapi += 3;
  } else {
    score.elevenlabs += 2;
  }

  // Rule 4: Length profile (ignore spaces)
  if (v.length <= 12) {
    score.vapi += 2;
  } else if (v.length >= 16) {
    score.elevenlabs += 2;
  }

  // Rule 5: Case entropy
  const hasUpper = /[A-Z]/.test(v);
  const hasLower = /[a-z]/.test(v);

  if (hasUpper && hasLower) {
    score.elevenlabs += 1;
  } else {
    score.vapi += 1;
  }

  // Rule 6: Name-like structure (each word TitleCase)
  if (/^([A-Z][a-z]+)(\s[A-Z][a-z]+)*$/.test(original)) {
    score.vapi += 3;
  }

  // Final decision
  return score.elevenlabs > score.vapi ? "elevenlabs" : "vapi";
}

